diff -u -r -N linux-2.6.8.1/drivers/acpi/hardware/hwsleep.c linux-2.6.8.1-acpifix/drivers/acpi/hardware/hwsleep.c
--- linux-2.6.8.1/drivers/acpi/hardware/hwsleep.c	2004-08-16 09:53:05.000000000 +0200
+++ linux-2.6.8.1-acpifix/drivers/acpi/hardware/hwsleep.c	2004-08-16 10:00:41.257905209 +0200
@@ -284,6 +284,11 @@
 		if (ACPI_FAILURE (status)) {
 			return_ACPI_STATUS (status);
 		}
+	} else {
+		status = acpi_hw_clear_acpi_status (ACPI_MTX_DO_NOT_LOCK);
+		if (ACPI_FAILURE (status)) {
+		return_ACPI_STATUS (status);
+		}
 	}

